# Update docs

Please update the docs.

In particular mention the support for Recursive Language Models, configurable with the LUA builtin toolbox like the following

```json
{
  "tag": "OpenAIAgentDescription",
  "contents": {
    "slug": "local_lrmlua",
    "flavor": "KimiV1",
    "modelUrl": "https://api.moonshot.ai/v1",
    "apiKeyId": "kimi",
    "modelName": "kimi-k2.5",
    "announce": "The main agent, capable of reasoning.",
    "systemPrompt": [
      "You are a helpful software agent trying to solve user requests"
    ],
    "extraAgents": [
      {
        "slug": "local_lrmlua",
        "path": "kimi-10.lrmlua.json"
      }
    ],
    "bashToolboxes": [
      {
        "tag": "SingleTool",
        "contents": "./tools/askuser/ask-user.bash"
      }
    ],
    "builtinToolboxes": [
      {
        "tag": "LuaToolbox",
        "contents": {
          "Name": "lua",
          "Description": "Sandboxed Lua interpreter",
          "MaxMemoryMB": 256,
          "MaxExecutionTimeSeconds": 300,
          "AllowedTools": [
            "bash_ask_user",
            "io_prompt_agent_local_lrmlua",
            "sqlite_shared_working_memory_query"
          ],
          "AllowedPaths": [
            "./repro-cases",
            "./README.md"
          ],
          "AllowedHosts": [
            "localhost",
            "127.0.0.1"
          ]
        }
      },
      {
        "tag": "SqliteToolbox",
        "contents": {
          "Name": "shared_working_memory",
          "Description": "A base to help you coordinate large works.",
          "Path": "./dev-memory.db",
          "Access": "read-write"
        }
      }
    ]
  }
}

```

